// ============================================
// BUILD REQUEST - Assembles the OpenAI API call
// ============================================

// Get trigger data
const trigger = $('Telegram Trigger').first().json;
const chatId = String(trigger.message.chat.id);
const messageText = trigger.message.text || '';
const firstName = trigger.message.from.first_name || 'there';
const username = trigger.message.from.username || '';

// Find existing lead in Leads sheet
const allLeads = $('Read Leads').all().map(i => i.json);
const existingLead = allLeads.find(l => String(l.chat_id) === chatId);
const isNewLead = !existingLead || !existingLead.chat_id;

// Get conversation history for this chat_id
const allConvos = $('Read Conversations').all().map(i => i.json);
const myHistory = allConvos
  .filter(c => String(c.chat_id) === chatId)
  .sort((a, b) => new Date(a.timestamp) - new Date(b.timestamp))
  .slice(-20);

// ---- SYSTEM PROMPT ----
const systemPrompt = `You are Noor, a client relations specialist at Fatima Habna Art Studio in Dubai. You chat with potential clients on Telegram who are interested in custom artwork. You have deep knowledge of the Dubai art scene and luxury interiors market.

HOW YOU TALK:
- Keep it casual and warm, like texting a friend who knows everything about art
- Short messages. 2-4 sentences max. Nobody reads novels on Telegram
- Use line breaks between thoughts
- Never use bullet points or numbered lists in chat
- Occasionally use expressions like beautiful choice, love that vision, great taste
- Never say I am an AI or as an AI
- Never use the word assist - say help instead
- Do not be overly enthusiastic or salesy. Be genuine.
- Mirror the client language style
- Detect language and respond in the same language (Arabic, English, or Russian)

YOUR GOAL (in order):
1. Build rapport - make them feel their vision matters
2. Understand what they want (style, size, space, budget, timeline, purpose)
3. Answer questions honestly about process, pricing, and timelines
4. If they seem ready, suggest a free consultation with Fatima
5. If not ready, keep the door open warmly

QUALIFYING QUESTIONS (ask naturally, not like a form):
- What kind of artwork are you envisioning?
- Where will the piece live? (home, office, hotel, restaurant)
- Do you have a sense of the size you need?
- Any styles or colors that speak to you?
- What is your budget range?
- When would you like the piece completed?

ART MARKET KNOWLEDGE:
- Small custom paintings (up to 60x60cm): AED 2,000 - 5,000
- Medium canvas (60x90cm - 90x120cm): AED 5,000 - 15,000
- Large canvas (120x150cm+): AED 15,000 - 40,000
- Extra large / murals: AED 40,000 - 150,000+
- Corporate installations: Custom quote
- Arabic calligraphy is very popular in Dubai luxury interiors
- Abstract and contemporary are trending in new villa developments
- Hotels and restaurants often commission series of 5-10 coordinated pieces
- Commission timeline: 4-12 weeks depending on size and complexity
- Process: Consultation > Concept > Approval > Creation > Delivery

WHEN TO SUGGEST CONSULTATION:
If client has shared style preference + approximate size + timeline within 3 months, suggest: I could set up a free consultation with Fatima to discuss your vision in detail - she loves hearing directly what clients imagine. Would that work for you?

WHEN TO HAND OFF:
If client asks about corporate installations, projects over AED 25,000, or very specific technical questions - say: Let me connect you with Fatima directly for that - she handles all the creative direction for projects like this and can give you exact details.

WHAT NOT TO DO:
- Do not make up specific availability or exact prices
- Do not promise specific completion dates without consultation
- Do not push. If someone says they are just exploring, respect that
- Do not ask multiple questions in one message

OUTPUT FORMAT:
You must respond in valid JSON with exactly two fields:
1. reply - your message to send to the client
2. lead_data - an object with any NEW information learned from THIS message only

For lead_data fields, set to null if no new info was learned. Fields:
- status: new | cold | warm | hot | consultation_booked | handed_off
- budget_min: number in AED or null
- budget_max: number in AED or null
- style_preference: string (abstract, calligraphy, contemporary, realism, mixed media, etc.) or null
- artwork_type: painting | mural | sculpture | calligraphy | installation | mixed_media or null
- size_preference: small | medium | large | extra_large | mural or null
- space_type: villa | apartment | office | hotel | restaurant | retail | outdoor or null
- purpose: personal | gift | commercial | investment | interior_design_project or null
- timeline: immediate | 1-3_months | 3-6_months | exploring or null
- quantity: number or null (for multi-piece commissions)
- phone: string or null
- email: string or null
- notes: brief important note or null
- wants_consultation: true/false/null
- wants_handoff: true/false/null

STATUS LOGIC:
- new: First message, no info yet
- cold: Just browsing, no timeline, vague interest
- warm: Has shared some preferences (style OR size OR budget)
- hot: Has style + approximate budget + timeline within 3 months
- consultation_booked: Free consultation scheduled
- handed_off: Connected to Fatima directly`;

// Build messages array
const messages = [{ role: 'system', content: systemPrompt }];

// Add lead context if returning user
if (existingLead && existingLead.status) {
  const ctx = ['Current lead profile:'];
  if (existingLead.status) ctx.push('- Status: ' + existingLead.status);
  if (existingLead.budget_min) ctx.push('- Budget min: AED ' + existingLead.budget_min);
  if (existingLead.budget_max) ctx.push('- Budget max: AED ' + existingLead.budget_max);
  if (existingLead.style_preference) ctx.push('- Style: ' + existingLead.style_preference);
  if (existingLead.artwork_type) ctx.push('- Artwork type: ' + existingLead.artwork_type);
  if (existingLead.size_preference) ctx.push('- Size: ' + existingLead.size_preference);
  if (existingLead.space_type) ctx.push('- Space: ' + existingLead.space_type);
  if (existingLead.purpose) ctx.push('- Purpose: ' + existingLead.purpose);
  if (existingLead.timeline) ctx.push('- Timeline: ' + existingLead.timeline);
  if (existingLead.quantity) ctx.push('- Quantity: ' + existingLead.quantity);
  if (existingLead.notes) ctx.push('- Notes: ' + existingLead.notes);
  if (existingLead.message_count) ctx.push('- Messages exchanged: ' + existingLead.message_count);
  messages.push({ role: 'system', content: ctx.join('\n') });
}

// Add conversation history
for (const conv of myHistory) {
  const role = conv.direction === 'inbound' ? 'user' : 'assistant';
  // For assistant messages, extract just the reply text if it was stored as JSON
  let content = conv.message;
  if (role === 'assistant') {
    try {
      const parsed = JSON.parse(content);
      if (parsed.reply) content = parsed.reply;
    } catch(e) { /* not JSON, use as-is */ }
  }
  messages.push({ role, content });
}

// Add current message
messages.push({ role: 'user', content: messageText });

// Build the full OpenAI request body
const requestBody = {
  model: 'gpt-4o-mini',
  messages: messages,
  response_format: {
    type: 'json_schema',
    json_schema: {
      name: 'agent_response',
      strict: true,
      schema: {
        type: 'object',
        required: ['reply', 'lead_data'],
        additionalProperties: false,
        properties: {
          reply: { type: 'string' },
          lead_data: {
            type: 'object',
            additionalProperties: false,
            required: ['status', 'budget_min', 'budget_max', 'style_preference', 'artwork_type', 'size_preference', 'space_type', 'purpose', 'timeline', 'quantity', 'phone', 'email', 'notes', 'wants_consultation', 'wants_handoff'],
            properties: {
              status: { type: ['string', 'null'] },
              budget_min: { type: ['number', 'null'] },
              budget_max: { type: ['number', 'null'] },
              style_preference: { type: ['string', 'null'] },
              artwork_type: { type: ['string', 'null'] },
              size_preference: { type: ['string', 'null'] },
              space_type: { type: ['string', 'null'] },
              purpose: { type: ['string', 'null'] },
              timeline: { type: ['string', 'null'] },
              quantity: { type: ['number', 'null'] },
              phone: { type: ['string', 'null'] },
              email: { type: ['string', 'null'] },
              notes: { type: ['string', 'null'] },
              wants_consultation: { type: ['boolean', 'null'] },
              wants_handoff: { type: ['boolean', 'null'] }
            }
          }
        }
      }
    }
  },
  temperature: 0.7,
  max_tokens: 500
};

return [{
  json: {
    chatId,
    firstName,
    username,
    messageText,
    isNewLead,
    existingLead: existingLead || {},
    requestBody,
    timestamp: new Date().toISOString()
  }
}];

// ================================================
// PROCESS RESPONSE - Parse AI output + prepare data
// ================================================

const openaiResponse = $input.first().json;
const buildData = $('Build Request').first().json;

// Parse the AI response
let aiContent;
try {
  aiContent = JSON.parse(openaiResponse.choices[0].message.content);
} catch(e) {
  // Fallback if JSON parsing fails
  aiContent = {
    reply: openaiResponse.choices[0].message.content || 'Sorry, I had a moment there. Could you say that again?',
    lead_data: { status: null }
  };
}

const reply = aiContent.reply;
const newData = aiContent.lead_data || {};

// Filter out null values from new lead data
const cleanNewData = {};
for (const [key, value] of Object.entries(newData)) {
  if (value !== null && value !== undefined) {
    cleanNewData[key] = value;
  }
}

// Merge with existing lead data
const existing = buildData.existingLead || {};
const merged = { ...existing };

// Only overwrite with genuinely new values
for (const [key, value] of Object.entries(cleanNewData)) {
  merged[key] = value;
}

// Set metadata
merged.chat_id = buildData.chatId;
merged.first_name = merged.first_name || buildData.firstName;
merged.username = merged.username || buildData.username;
merged.last_contact = buildData.timestamp;
merged.message_count = (parseInt(merged.message_count) || 0) + 1;

if (buildData.isNewLead) {
  merged.first_contact = buildData.timestamp;
  merged.follow_up_count = 0;
  if (!merged.status) merged.status = 'new';
}

// Should we notify the owner?
const notifyOwner = (
  merged.status === 'hot' ||
  cleanNewData.wants_consultation === true ||
  cleanNewData.wants_handoff === true
);

// Build owner notification message
let ownerMessage = '';
if (notifyOwner) {
  ownerMessage = '\ud83d\udd25 HOT LEAD ALERT!\n\n';
  ownerMessage += 'Name: ' + (merged.first_name || 'Unknown') + '\n';
  ownerMessage += 'Telegram: @' + (merged.username || 'N/A') + '\n';
  ownerMessage += 'Status: ' + (merged.status || 'unknown') + '\n';
  if (merged.budget_min || merged.budget_max) {
    ownerMessage += 'Budget: AED ' + (merged.budget_min || '?') + ' - ' + (merged.budget_max || '?') + '\n';
  }
  if (merged.style_preference) ownerMessage += '\ud83c\udfa8 Style: ' + merged.style_preference + '\n';
  if (merged.artwork_type) ownerMessage += '\ud83d\uddbc\ufe0f Artwork: ' + merged.artwork_type + '\n';
  if (merged.size_preference) ownerMessage += '\ud83d\udccf Size: ' + merged.size_preference + '\n';
  if (merged.space_type) ownerMessage += '\ud83c\udfe0 Space: ' + merged.space_type + '\n';
  if (merged.timeline) ownerMessage += 'Timeline: ' + merged.timeline + '\n';
  if (merged.purpose) ownerMessage += 'Purpose: ' + merged.purpose + '\n';
  if (merged.quantity) ownerMessage += 'Quantity: ' + merged.quantity + '\n';
  ownerMessage += '\nLatest message: ' + buildData.messageText;
  if (cleanNewData.wants_consultation) ownerMessage += '\n\n\u2728 WANTS A FREE CONSULTATION';
  if (cleanNewData.wants_handoff) ownerMessage += '\n\n\ud83d\udcde WANTS TO SPEAK TO FATIMA';
}

return [{
  json: {
    reply,
    chatId: buildData.chatId,
    firstName: buildData.firstName,
    username: buildData.username,
    messageText: buildData.messageText,
    isNewLead: buildData.isNewLead,
    notifyOwner,
    ownerMessage,
    timestamp: buildData.timestamp,
    leadData: merged,
    newExtracted: cleanNewData
  }
}];
